  5→//! JJK Tally commands - pace modification operations
  6→//!
  7→//! Split into four single-purpose commands:
  8→//! - revise_docket: Update pace docket text
  9→//! - arm: Set state to bridled with warrant
 10→//! - relabel: Rename pace silks
 11→//! - drop: Set state to abandoned
 12→
 13→use std::path::PathBuf;
 14→
 15→use crate::jjrf_favor::jjrf_Coronet as Coronet;
 16→use crate::jjrg_gallops::{jjrg_Gallops as Gallops, jjrg_PaceState as PaceState};
 17→use crate::jjrn_notch::{jjrn_format_heat_message as format_heat_message, jjrn_HeatAction as HeatAction};
 18→
 19→/// Arguments for jjx_revise_docket command
 20→#[derive(clap::Args, Debug)]
 21→pub struct jjrtl_ReviseDocketArgs {
 22→    /// Path to the Gallops JSON file
 23→    #[arg(long, short = 'f', default_value = ".claude/jjm/jjg_gallops.json")]
 24→    pub file: PathBuf,
 25→
 26→    /// Target Pace identity (Coronet)
 27→    pub coronet: String,
 28→}
 29→
 30→/// Run the revise_docket command
 31→///
 32→/// Updates the docket text for a pace.
 33→pub fn jjrtl_run_revise_docket(args: jjrtl_ReviseDocketArgs, docket: String) -> i32 {
 34→    use crate::jjrg_gallops::jjrg_TallyArgs as LibTallyArgs;
 35→
 36→    // Acquire lock FIRST - fail fast if another operation is in progress
 37→    let lock = match vvc::vvcc_CommitLock::vvcc_acquire() {
 38→        Ok(l) => l,
 39→        Err(e) => {
 40→            eprintln!("jjx_revise_docket: error: {}", e);
 41→            return 1;
 42→        }
 43→    };
 44→
 45→    let text = docket;
 46→
 47→    let mut gallops = match Gallops::jjrg_load(&args.file) {
 48→        Ok(g) => g,
 49→        Err(e) => {
 50→            eprintln!("jjx_revise_docket: error loading Gallops: {}", e);
 51→            return 1;
 52→        }
 53→    };
 54→
 55→    // Get firemark and silks for commit message before we move args
 56→    let coronet_str = args.coronet.clone();
 57→    let (fm, silks) = match Coronet::jjrf_parse(&coronet_str) {
 58→        Ok(c) => {
 59→            let parent_fm = c.jjrf_parent_firemark();
 60→            let silks = gallops.heats.get(&parent_fm.jjrf_display())
 61→                .and_then(|h| h.paces.get(&c.jjrf_display()))
 62→                .and_then(|p| p.tacks.first().map(|t| t.silks.clone()))
 63→                .unwrap_or_else(|| coronet_str.clone());
 64→            (parent_fm, silks)
 65→        }
 66→        Err(e) => {
 67→            eprintln!("jjx_revise_docket: error: {}", e);
 68→            return 1;
 69→        }
 70→    };
 71→
 72→    let tally_args = LibTallyArgs {
 73→        coronet: args.coronet,
 74→        state: None,
 75→        direction: None,
 76→        text: Some(text),
 77→        silks: None,
 78→    };
 79→
 80→    match gallops.jjrg_tally(tally_args) {
 81→        Ok(()) => {
 82→            let message = format_heat_message(&fm, HeatAction::Tally, &silks);
 83→
 84→            match crate::jjri_io::jjri_persist(&lock, &gallops, &args.file, &fm, message, 50000) {
 85→                Ok(hash) => {
 86→                    println!("committed {}", hash);
 87→                    0
 88→                }
 89→                Err(e) => {
 90→                    eprintln!("jjx_revise_docket: error: {}", e);
 91→                    1
 92→                }
 93→            }
 94→        }
 95→        Err(e) => {
 96→            eprintln!("jjx_revise_docket: error: {}", e);
 97→            1
 98→        }
 99→    }
100→    // lock released here
101→}
