14→/// Arguments for jjx_slate command
15→#[derive(Args, Debug)]
16→pub struct jjrsl_SlateArgs {
17→    /// Path to the Gallops JSON file
18→    #[arg(long, short = 'f', default_value = ".claude/jjm/jjg_gallops.json")]
19→    pub file: PathBuf,
20→
21→    /// Target Heat identity (Firemark)
22→    pub firemark: String,
23→
24→    /// Kebab-case display name for the Pace
25→    #[arg(long, short = 's')]
