41→/// Handler for jjx_slate command
42→pub fn jjrsl_run_slate(args: jjrsl_SlateArgs, docket: String) -> i32 {
43→    use crate::jjrg_gallops::jjrg_SlateArgs as LibSlateArgs;
44→
45→    // Acquire lock FIRST - fail fast if another operation is in progress
46→    let lock = match vvc::vvcc_CommitLock::vvcc_acquire() {
47→        Ok(l) => l,
48→        Err(e) => {
49→            eprintln!("jjx_slate: error: {}", e);
50→            return 1;
51→        }
52→    };
53→
54→    let text = docket;
55→
56→    let mut gallops = match Gallops::jjrg_load(&args.file) {
57→        Ok(g) => g,
58→        Err(e) => {
59→            eprintln!("jjx_slate: error loading Gallops: {}", e);
60→            return 1;
61→        }
62→    };
63→
64→    let firemark = args.firemark.clone();
65→    let silks = args.silks.clone();
66→    let slate_args = LibSlateArgs {
67→        firemark: args.firemark,
68→        silks: args.silks,
69→        text,
70→        before: args.before,
71→        after: args.after,
72→        first: args.first,
73→    };
74→
75→    match gallops.jjrg_slate(slate_args) {
76→        Ok(result) => {
77→            let fm = Firemark::jjrf_parse(&firemark).expect("slate given invalid firemark");
78→            let message = format_heat_message(&fm, HeatAction::Slate, &silks);
79→
80→            match crate::jjri_io::jjri_persist(&lock, &gallops, &args.file, &fm, message, 50000) {
